INSERT INTO quiz_questions (set_id, question_id, question, options, correct_option_index, explanation, sort_order) VALUES
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_51', '"거절하다"를 영어로?', '["Refuse","Receive","Reduce","Remove"]', 0, '"Refuse"는 거절하다입니다.', 51),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_52', '"줄이다"를 영어로?', '["Refuse","Receive","Reduce","Remove"]', 2, '"Reduce"는 줄이다입니다.', 52),
