((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_54', 'She asked me ___ I could help her.', '["that","if","what","which"]', 1, '간접 의문문: if = ~인지 아닌지.', 54),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_55', 'He suggested ___ we go to the park.', '["if","that","what","which"]', 1, 'suggest + that절.', 55),
