((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_57', '"carry out"의 뜻은?', '["운반하다","수행하다","들고 나가다","참다"]', 1, '"carry out" = 수행하다/실행하다.', 57),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_58', '"set up"의 뜻은?', '["앉다","설립하다/설치하다","정리하다","멈추다"]', 1, '"set up" = 설립하다/설치하다.', 58),
