((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_60', 'If I had studied harder, I ___ passed the exam.', '["will have","would have","could","should"]', 1, '가정법 과거완료: would have + p.p.', 60),
